function expandWhyRecommendation(baseWhy: string): string {
  return `${baseWhy} We prioritize tools that are proven in real small-business operations: reliable mobile clock-ins, clean supervisor approvals, and payroll exports that reduce manual correction time. Each recommendation is weighted for day-to-day usability, reporting clarity, and practical implementation risk so teams can improve labor accuracy without adding unnecessary process overhead.`;
}

function buildEnhancedFaqItems(config: TradeConfig): BestForFaqItem[] {
  const normalizedUseCase = config.useCase.replace(/-/g, " ");
  const titleKeyword = config.title.replace(" (2026)", "");
  const faqSeed: BestForFaqItem[] = [
    {
      q: `What is the best time tracking software for ${normalizedUseCase}?`,
      a: `${titleKeyword} usually depends on how your team works in the field and office. We recommend starting with the top pick on this page, running a 2-4 week pilot, and validating adoption rate, payroll export accuracy, and job-level labor reporting before full rollout.`,
    },
    {
      q: `What features matter most when choosing time tracking software for ${normalizedUseCase}?`,
      a: "Prioritize mobile ease of use, role-based approvals, reliable reporting, and integrations with payroll or invoicing workflows. For field teams, GPS/geofencing and simple clock rules often matter more than advanced monitoring features.",
    },
    {
      q: "How can I evaluate time tracking software with confidence?",
      a: "Use a real pay-cycle test with active jobs, not a demo-only trial. Compare missed clock-ins, payroll correction workload, and manager approval time before and after rollout. The best tool is the one your team uses consistently while producing cleaner labor and payroll data.",
    },
  ];

  const combined = [...config.faqItems, ...faqSeed];
  return combined.filter((item, index, arr) => arr.findIndex((x) => x.q === item.q) === index);
}

function buildPageData(config: TradeConfig, navLabel: string): TradePageData {
  const featuredProducts: BestForFeaturedProduct[] = config.picks.map((pick) => {
    const product = PRODUCT_CORE[pick.slug];
    return {
      slug: pick.slug,
      name: product.name,
      badge: pick.badge,
      description: pick.description,
      rating: product.rating,
      startingPrice: product.startingPrice,
      reviewHref: getTimeTrackingReviewUrl(pick.slug),
      visitUrl: product.visitUrl,
      logoSrc: product.logoSrc,
    };
  });

  const comparisonTableRows: BestForTableRow[] = config.picks.map((pick) => {
    const product = PRODUCT_CORE[pick.slug];
    return {
      slug: pick.slug,
      name: product.name,
      logoSrc: product.logoSrc,
      bestFor: pick.rowBestFor,
      startingPrice: product.startingPrice,
      standoutFeature: pick.standoutFeature ?? product.defaultStandout,
      reviewHref: getTimeTrackingReviewUrl(pick.slug),
    };
  });

  const whyThesePicks: BestForEditorialBlock[] = config.picks.map((pick) => ({
    heading: PRODUCT_CORE[pick.slug].name,
    body: expandWhyRecommendation(pick.why),
  }));

  const relatedReviews: BestForReviewLink[] = config.picks.map((pick) => ({
    name: PRODUCT_CORE[pick.slug].name,
    href: getTimeTrackingReviewUrl(pick.slug),
  }));

  return {
    pageProps: {
      title: config.title,
      subtitle: config.subtitle,
      useCase: config.useCase,
      categoryHref: CATEGORY.href,
      categoryLabel: CATEGORY.label,
      introParagraph: config.introParagraph,
      freshnessText: "Updated for 2026",
      topPicksSub: "Our top time tracking picks for this trade.",
      editorialSub: "What to look for when choosing time tracking software for this business type.",
      whyThesePicksSub: "Why these tools made our shortlist.",
      seeAlsoBlock: SEE_ALSO,
      featuredProducts,
      comparisonTableRows,
      editorialGuidance: config.editorialGuidance,
      whyThesePicks,
      relatedReviews,
      relatedComparisons: COMMON_COMPARISONS,
      relatedGuides: COMMON_GUIDES,
      faqItems: buildEnhancedFaqItems(config),
    },
    metadata: {
      title: buildBestForMetaTitle(config.title),
      description: config.subtitle,
      keywords: config.keywords,
    },
    hubTeaser: config.hubTeaser,
    navLabel,
  };
}

